import '../App.css';
import '../../node_modules/bootstrap/dist/css/bootstrap.css'
import React, { useState, useEffect, useCallback } from 'react';
import { Link, NavLink, useNavigate } from 'react-router-dom';
import axios from 'axios';



// const columns = [{
//   dataField: 'id',
//   text: 'ID'
// }, {
//   dataField: 'name_sing',
//   text: 'Название дорожного знака'
// }];

const api = axios.create({ 
    baseURL: 'http://localhost:5000',
    withCredentials: true 
});

function Sing() {
  const [tableData, setTableData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [debugInfo, setDebugInfo] = useState({});
  const navigate = useNavigate();

  const fetchTableData = useCallback(async () => {
    setLoading(true);
    setError('');

    try {
      const response = await api.get('/sings');

      setDebugInfo({
        status: response.status,
        timestamp: new Date().toISOString(),
        dataLength: response.data?.length || 0
      });

      if (response.status === 200) {
        setTableData(Array.isArray(response.data) ? response.data : [response.data]);
      }
    } catch (err) {
      let errorMessage = '';

      if (err.response) {
        errorMessage = err.response.data.message || `Ошибка ${err.response.status}`;
        setDebugInfo(prev => ({
          ...prev,
          errorResponse: err.response.data,
          errorStatus: err.response.status
        }));

        if (err.response.status === 401) {
          setTimeout(() => navigate('/login'), 1500);
        }
      } else if (err.request) {
        errorMessage = 'Нет ответа от сервера';
      } else {
        errorMessage = 'Ошибка при отправке запроса';
      }

      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  }, [navigate]);

  useEffect(() => {
    fetchTableData();
  }, [fetchTableData]);

  const renderTable = () => {
    if (tableData.length === 0) {
      return <p className="no-data">Нет данных для отображения</p>;
    }

    const headers = Object.keys(tableData[0]);

    return (
      <div className="table-wrapper">
        <table className="data-table">
          <thead>
            <tr>
              {headers.map(header => (
                <th key={header}>{header}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {tableData.map((row, index) => (
              <tr key={index}>
                {headers.map(header => (
                  <td key={`${index}-${header}`}>
                    {typeof row[header] === 'object' 
                      ? JSON.stringify(row[header]) 
                      : String(row[header])}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  };

  return (
    <div className="app-container">
      <div className="app-card">
        <div className="table-header">
          <h2 className="app-title">Защищенные данные</h2>
          <div className="header-actions">

          </div>
        </div>

        {error && (
          <div className={`error-message ${error.includes('401') ? 'auth-error' : ''}`}>
            <strong>Ошибка:</strong> {error}
            {error.includes('401') && (
              <button onClick={() => navigate('/login')} className="inline-action">
                Перейти к авторизации
              </button>
            )}
          </div>
        )}

        <div className="controls">
          <button
            onClick={fetchTableData}
            disabled={loading}
            className="refresh-button"
          >
            {loading ? 'Загрузка...' : 'Обновить данные'}
          </button>

          <button
            onClick={() => {
              setTableData([]);
              setDebugInfo({});
            }}
            className="clear-button"
          >
            Очистить
          </button>
        </div>

        <div className="data-section">
          <h3 className="section-title">
            Таблица данных {tableData.length > 0 && `(${tableData.length} записей)`}
          </h3>
          {renderTable()}
        </div>

        </div>
    </div>
  );
}

export default Sing;
